import{_ as e,o as n,c as s,ae as l}from"./chunks/framework.9mFzz-eW.js";const u=JSON.parse('{"title":"debug/debug-channel","description":"","frontmatter":{},"headers":[],"relativePath":"api/debug.debug-channel.md","filePath":"api/debug.debug-channel.md"}'),t={name:"api/debug.debug-channel.md"};function o(d,a,r,c,i,h){return n(),s("div",null,[...a[0]||(a[0]=[l(`<h1 id="debug-debug-channel" tabindex="-1">debug/debug-channel <a class="header-anchor" href="#debug-debug-channel" aria-label="Permalink to &quot;debug/debug-channel&quot;">​</a></h1><p>디버그 BroadcastChannel 통신 및 팝업 관리</p><p>같은 출처(Origin)의 모든 브라우저 탭이 <code>&#39;dsm_debug&#39;</code> 채널로 연결되어 디버그 팝업 창에서 모든 탭의 <code>DomainState</code> 상태를 실시간으로 확인할 수 있다.</p><h2 id="아키텍처-—-broadcastchannel-기반-멀티탭-통신" tabindex="-1">아키텍처 — BroadcastChannel 기반 멀티탭 통신 <a class="header-anchor" href="#아키텍처-—-broadcastchannel-기반-멀티탭-통신" aria-label="Permalink to &quot;아키텍처 — BroadcastChannel 기반 멀티탭 통신&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[탭 A]              [탭 B]              [디버그 팝업]</span></span>
<span class="line"><span>  │                   │                      │</span></span>
<span class="line"><span>  │◄──── TAB_PING ────┼──────────────────────│  팝업이 ping 전송</span></span>
<span class="line"><span>  │                   │                      │</span></span>
<span class="line"><span>  ├──── TAB_REGISTER ─┼──────────────────────►  각 탭이 자신을 등록</span></span>
<span class="line"><span>  │                   ├──── TAB_REGISTER ────►</span></span>
<span class="line"><span>  │                   │                      │</span></span>
<span class="line"><span>  ├──── DS_UPDATE ────┼──────────────────────►  상태 변경 시 broadcast</span></span>
<span class="line"><span>  │                   │                      │</span></span>
<span class="line"><span>  │ (탭 닫힘/새로고침)│                      │</span></span>
<span class="line"><span>  ├── TAB_UNREGISTER ─┼──────────────────────►  탭 해제 알림</span></span></code></pre></div><h2 id="broadcastchannel-자기-수신-불가-제약-우회" tabindex="-1">BroadcastChannel 자기 수신 불가 제약 우회 <a class="header-anchor" href="#broadcastchannel-자기-수신-불가-제약-우회" aria-label="Permalink to &quot;BroadcastChannel 자기 수신 불가 제약 우회&quot;">​</a></h2><p>BroadcastChannel은 자기 자신이 보낸 메시지를 수신하지 않는다. 따라서 팝업이 직접 <code>TAB_PING</code>을 broadcast하고, 각 탭이 <code>TAB_REGISTER</code>로 응답한다.</p><h2 id="heartbeat-gc-전략" tabindex="-1">Heartbeat &amp; GC 전략 <a class="header-anchor" href="#heartbeat-gc-전략" aria-label="Permalink to &quot;Heartbeat &amp; GC 전략&quot;">​</a></h2><p>팝업은 2초마다 <code>TAB_PING</code>을 전송하고, 탭은 <code>TAB_REGISTER</code>로 응답한다. 팝업의 GC 로직이 2초마다 <code>lastSeen</code> 타임스탬프를 확인하여 5초 이상 응답이 없는 탭을 죽은 탭으로 판단하고 레지스트리에서 제거한다. <code>beforeunload</code> 이벤트에 의존하지 않아 모바일 브라우저나 강제 종료에도 대응한다.</p><h2 id="메모리-누수-방지" tabindex="-1">메모리 누수 방지 <a class="header-anchor" href="#메모리-누수-방지" aria-label="Permalink to &quot;메모리 누수 방지&quot;">​</a></h2><p>SPA 환경에서 컴포넌트가 언마운트될 때 <code>closeDebugChannel()</code>을 호출하여 <code>BroadcastChannel</code>을 명시적으로 닫고 GC 대상이 되도록 해야 한다.</p><h2 id="모듈-로드-시-사이드-이펙트" tabindex="-1">모듈 로드 시 사이드 이펙트 <a class="header-anchor" href="#모듈-로드-시-사이드-이펙트" aria-label="Permalink to &quot;모듈 로드 시 사이드 이펙트&quot;">​</a></h2><p>이 모듈은 import 시 자동으로 아래 동작을 수행한다:</p><ol><li><code>getChannel()</code>을 통해 채널 인스턴스를 초기화</li><li><code>TAB_PING</code> 수신 시 <code>registerTab()</code> 응답 리스너 등록</li><li><code>beforeunload</code> 시 <code>TAB_UNREGISTER</code> 전송 리스너 등록</li><li>초기 <code>registerTab()</code> 호출 (페이지 로드 직후 자기 등록)</li></ol><h2 id="see" tabindex="-1">See <a class="header-anchor" href="#see" aria-label="Permalink to &quot;See&quot;">​</a></h2><ul><li><a href="https://developer.mozilla.org/ko/docs/Web/API/BroadcastChannel" target="_blank" rel="noreferrer">MDN — BroadcastChannel</a></li><li>module:domain/DomainState DomainState</li></ul><h2 id="interfaces" tabindex="-1">Interfaces <a class="header-anchor" href="#interfaces" aria-label="Permalink to &quot;Interfaces&quot;">​</a></h2><ul><li><a href="./debug.debug-channel.Interface.BroadcastSnapshot.html">BroadcastSnapshot</a></li><li><a href="./debug.debug-channel.Interface.DomainStateSnapshot.html">DomainStateSnapshot</a></li><li><a href="./debug.debug-channel.Interface.DsErrorMessage.html">DsErrorMessage</a></li><li><a href="./debug.debug-channel.Interface.DsUpdateMessage.html">DsUpdateMessage</a></li><li><a href="./debug.debug-channel.Interface.TabRegisterMessage.html">TabRegisterMessage</a></li><li><a href="./debug.debug-channel.Interface.TabUnregisterMessage.html">TabUnregisterMessage</a></li></ul><h2 id="type-aliases" tabindex="-1">Type Aliases <a class="header-anchor" href="#type-aliases" aria-label="Permalink to &quot;Type Aliases&quot;">​</a></h2><ul><li><a href="./debug.debug-channel.TypeAlias.DebugMessageType.html">DebugMessageType</a></li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><ul><li><a href="./debug.debug-channel.Function.broadcastError.html">broadcastError</a></li><li><a href="./debug.debug-channel.Function.broadcastUpdate.html">broadcastUpdate</a></li><li><a href="./debug.debug-channel.Function.closeDebugChannel.html">closeDebugChannel</a></li><li><a href="./debug.debug-channel.Function.openDebugPopup.html">openDebugPopup</a></li></ul>`,22)])])}const b=e(t,[["render",o]]);export{u as __pageData,b as default};
